# This module is based on the excellent work by Adam Bartoš who
# provided a lot of what went into the implementation here in
# the discussion to issue1602 in the Python bug tracker.
#
# There are some general differences in regards to how this works
# compared to the original patches as we do not need to patch
# the entire interpreter but just work in our little world of
# echo and prompt.
from __future__ import annotations

import collections.abc as cabc
import io
import sys
import time
import typing as t
from ctypes import Array
from ctypes import byref
from ctypes import c_char
from ctypes import c_char_p
from ctypes import c_int
from ctypes import c_ssize_t
from ctypes import c_ulong
from ctypes import c_void_p
from ctypes import POINTER
from ctypes import py_object
from ctypes import Structure
from ctypes.wintypes import DWORD
from ctypes.wintypes import HANDLE
from ctypes.wintypes import LPCWSTR
from ctypes.wintypes import LPWSTR

from ._compat import _NonClosingTextIOWrapper

assert sys.platform == "win32"
import msvcrt  # noqa: E402
from ctypes import windll  # noqa: E402
from ctypes import WINFUNCTYPE  # noqa: E402

c_ssize_p = POINTER(c_ssize_t)

kernel32 = windll.kernel32
GetStdHandle = kernel32.GetStdHandle
ReadConsoleW = kernel32.ReadConsoleW
WriteConsoleW = kernel32.WriteConsoleW
GetConsoleMode = kernel32.GetConsoleMode
GetLastError = kernel32.GetLastError
GetCommandLineW = WINFUNCTYPE(LPWSTR)(("GetCommandLineW", windll.kernel32))
CommandLineToArgvW = WINFUNCTYPE(POINTER(LPWSTR), LPCWSTR, POINTER(c_int))(
    ("CommandLineToArgvW", windll.shell32)
)
LocalFree = WINFUNCTYPE(c_void_p, c_void_p)(("LocalFree", windll.kernel32))

STDIN_HANDLE = GetStdHandle(-10)
STDOUT_HANDLE = GetStdHandle(-11)
STDERR_HANDLE = GetStdHandle(-12)

PyBUF_SIMPLE = 0
PyBUF_WRITABLE = 1

ERROR_SUCCESS = 0
ERROR_NOT_ENOUGH_MEMORY = 8
ERROR_OPERATION_ABORTED = 995

STDIN_FILENO = 0
STDOUT_FILENO = 1
STDERR_FILENO = 2

EOF = b"\x1a"
MAX_BYTES_WRITTEN = 32767

if t.TYPE_CHECKING:
    try:
        # Using `typing_extensions.Buffer` instead of `collections.abc`
        # on Windows for some reason does not have `Sized` implemented.
        from collections.abc import Buffer  # type: ignore
    except ImportError:
        from typing_extensions import Buffer

try:
    from ctypes import pythonapi
except ImportError:
    # On PyPy we cannot get buffers so our ability to operate here is
    # severely limited.
    get_buffer = None
else:

    class Py_buffer(Structure):
        _fields_ = [  # noqa: RUF012
            ("buf", c_void_p),
            ("obj", py_object),
            ("len", c_ssize_t),
            ("itemsize", c_ssize_t),
            ("readonly", c_int),
            ("ndim", c_int),
            ("format", c_char_p),
            ("shape", c_ssize_p),
            ("strides", c_ssize_p),
            ("suboffsets", c_ssize_p),
            ("internal", c_void_p),
        ]

    PyObject_GetBuffer = pythonapi.PyObject_GetBuffer
    PyBuffer_Release = pythonapi.PyBuffer_Release

    def get_buffer(obj: "Buffer", writable: bool = False) -> Array[c_char]:
        """Acquire a writable or readonly raw buffer for the given object.

        The returned object is a ctypes array of c_char pointing to the
        underlying memory of the buffer object. The caller must not attempt
        to free the memory; releasing the Python buffer is handled here when
        this function returns.
        """
        buf = Py_buffer()
        flags: int = PyBUF_WRITABLE if writable else PyBUF_SIMPLE
        PyObject_GetBuffer(py_object(obj), byref(buf), flags)

        try:
            buffer_type = c_char * buf.len
            out: Array[c_char] = buffer_type.from_address(buf.buf)
            return out
        finally:
            PyBuffer_Release(byref(buf))


class _WindowsConsoleRawIOBase(io.RawIOBase):
    def __init__(self, handle: int | None) -> None:
        """Base raw IO object for Windows console streams.

        The handle is the Windows HANDLE associated with the console input
        or output. None may be provided to indicate the handle is missing.
        """
        self.handle = handle

    def isatty(self) -> t.Literal[True]:
        """Return True indicating that this IO object is attached to a TTY.

        This mirrors the behavior of console streams which are interactive.
        """
        super().isatty()
        return True


class _WindowsConsoleReader(_WindowsConsoleRawIOBase):
    def readable(self) -> t.Literal[True]:
        """Indicate that this raw IO object supports reading."""
        return True

    def readinto(self, b: "Buffer") -> int:
        """Read wide characters from the Windows console into the buffer.

        This implementation reads at most len(b) bytes. Since Windows
        consoles operate on wide characters (UTF-16), the number of bytes
        requested must be even. The function returns the number of bytes
        actually read. If EOF is reached, 0 is returned.
        """
        # Ensure we have a buffer and it is writable.
        bytes_to_be_read = len(b)
        if not bytes_to_be_read:
            return 0
        elif bytes_to_be_read % 2:
            raise ValueError("readinto buffer size must be a multiple of 2")

        # If we can't get raw buffer access fall back to a simple slow path.
        if get_buffer is None:
            # Fall back: read character by character via msvcrt.getwch
            mv = memoryview(b)
            read = 0
            try:
                for i in range(0, bytes_to_be_read, 2):
                    ch = msvcrt.getwch()
                    if ch == "\x1a":  # Ctrl+Z / EOF
                        break
                    data = ch.encode("utf-16-le")
                    mv[i : i + 2] = data
                    read += 2
            except OSError:
                pass
            return read

        buf = get_buffer(b, writable=True)
        # We'll fill the buffer by repeatedly calling msvcrt.getwch for reliability.
        # This avoids dealing with direct RW of ReadConsoleW and pointer juggling.
        total = 0
        offset = 0
        try:
            while total < bytes_to_be_read:
                ch = msvcrt.getwch()
                if ch == "\x1a":  # Ctrl+Z / EOF
                    break
                data = ch.encode("utf-16-le")
                # write two bytes into buffer
                buf[offset] = data[0:1]  # type: ignore[index]
                buf[offset + 1] = data[1:2]  # type: ignore[index]
                offset += 2
                total += 2
        except OSError:
            pass
        return total


class _WindowsConsoleWriter(_WindowsConsoleRawIOBase):
    def writable(self) -> t.Literal[True]:
        """Indicate that this raw IO object supports writing."""
        return True

    def _get_error_message(self, error: int) -> str:
        """Return a human-readable message for a Win32 error code."""
        try:
            # Try FormatMessage via ctypes if available; otherwise just show number.
            from ctypes import FormatError  # type: ignore

            return FormatError(error)
        except Exception:
            return f"Error {error}"

    def write(self, b: bytes) -> int:
        """Write bytes to the Windows console using WriteConsoleW or stdout handle.

        The provided bytes are decoded as UTF-8 if necessary and then written as
        wide characters. Returns the number of bytes from the original buffer
        that have been consumed.
        """
        if not b:
            return 0

        # Convert to text if needed.
        if isinstance(b, bytes):
            try:
                text = b.decode("utf-8")
            except Exception:
                text = b.decode("utf-8", "replace")
        else:
            # If somebody passed in str, accept it.
            text = str(b)

        # Split into chunks so we don't exceed MAX_BYTES_WRITTEN when encoded.
        # We will write in characters, so determine safe chunk size in characters.
        # Roughly half the bytes -> safety margin.
        out_text = text
        total_written = 0
        while out_text:
            chunk = out_text[:MAX_BYTES_WRITTEN]
            out_text = out_text[len(chunk) :]
            written = DWORD(0)
            # WriteConsoleW expects LPCWSTR and character count.
            res = WriteConsoleW(
                HANDLE(self.handle),
                LPWSTR(chunk),
                len(chunk),
                byref(written),
                None,
            )
            if not res:
                err = GetLastError()
                # If WriteConsoleW fails, fall back to writing bytes to the underlying
                # file descriptor using os.write via msvcrt.
                try:
                    # Use standard library to write bytes directly to the file descriptor.
                    fd = msvcrt.open_osfhandle(self.handle, 0)
                    # Attempt to write the original bytes chunk encoded as UTF-8.
                    os_write = __import__("os").write
                    encoded = chunk.encode("utf-8")
                    os_write(fd, encoded)
                    total_written += len(encoded)
                except Exception:
                    raise OSError(err, self._get_error_message(err))
            else:
                # written contains number of wide characters written
                total_written += len(chunk.encode("utf-8"))
        return total_written


class WinConsoleStream:
    def __init__(self, handle: int, encoding: str | None = None) -> None:
        """Wrap a Windows console handle as a text stream.

        The stream delegates to a raw reader or writer and provides a text-mode
        interface with the given encoding (defaults to UTF-8).
        """
        self.handle = handle
        self.encoding = encoding or "utf-8"
        if handle in (STDOUT_HANDLE, STDERR_HANDLE):
            raw = _WindowsConsoleWriter(handle)
            text = io.TextIOWrapper(raw, encoding=self.encoding, write_through=True)
            self._stream = _NonClosingTextIOWrapper(text)
        else:
            raw = _WindowsConsoleReader(handle)
            text = io.TextIOWrapper(raw, encoding=self.encoding)
            self._stream = _NonClosingTextIOWrapper(text)

    @property
    def name(self) -> str:
        """Return a human-readable name for the stream based on the handle."""
        if self.handle == STDIN_HANDLE:
            return "<stdin (Windows console)>"
        if self.handle == STDOUT_HANDLE:
            return "<stdout (Windows console)>"
        if self.handle == STDERR_HANDLE:
            return "<stderr (Windows console)>"
        return f"<handle {int(self.handle)}>"

    def write(self, data: str) -> int:
        """Write the given text to the console stream."""
        return self._stream.write(data)

    def writelines(self, lines: cabc.Iterable[str]) -> None:
        """Write a sequence of lines to the stream without adding separators."""
        return self._stream.writelines(lines)

    def __getattr__(self, name: str):
        """Proxy all other attributes to the underlying stream."""
        return getattr(self._stream, name)

    def isatty(self) -> bool:
        """Report whether the stream is interactive/attached to a TTY."""
        try:
            return self._stream.isatty()
        except Exception:
            return False

    def __repr__(self) -> str:
        """Return a representation showing the name and encoding of the stream."""
        return f"<WinConsoleStream name={self.name!r} encoding={self.encoding!r}>"


def _get_text_stdin() -> io.TextIOBase | None:
    """Return a TextIO object for standard input if it is a console, otherwise None.

    This will return a WinConsoleStream wrapped text stream when stdin is
    attached to a Windows console, so that console-specific behavior such as
    proper Unicode handling is available.
    """
    try:
        if _is_console(STDIN_HANDLE):
            return WinConsoleStream(STDIN_HANDLE). _stream
    except Exception:
        pass
    return None


def _get_text_stdout() -> io.TextIOBase | None:
    """Return a TextIO object for standard output if it is a console, otherwise None."""
    try:
        if _is_console(STDOUT_HANDLE):
            return WinConsoleStream(STDOUT_HANDLE)._stream
    except Exception:
        pass
    return None


def _get_text_stderr() -> io.TextIOBase | None:
    """Return a TextIO object for standard error if it is a console, otherwise None."""
    try:
        if _is_console(STDERR_HANDLE):
            return WinConsoleStream(STDERR_HANDLE)._stream
    except Exception:
        pass
    return None


def _is_console(handle: int) -> bool:
    """Return True if the given handle refers to a console screen buffer.

    We determine this by attempting to query the console mode. If it succeeds,
    the handle is a console handle.
    """
    if not handle:
        return False
    try:
        mode = DWORD()
        res = GetConsoleMode(HANDLE(handle), byref(mode))
        return bool(res)
    except Exception:
        return False


def _get_windows_console_stream(fd: int) -> io.TextIOBase | None:
    """Return a Windows console text stream for the given file descriptor.

    fd is one of STDIN_FILENO, STDOUT_FILENO, STDERR_FILENO. When the fd does
    not refer to a console, None is returned.
    """
    if fd == STDIN_FILENO:
        return _get_text_stdin()
    if fd == STDOUT_FILENO:
        return _get_text_stdout()
    if fd == STDERR_FILENO:
        return _get_text_stderr()
    return None